// Helper to build minimal HookInput
function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Write',
    session_id: 'test-session',
    tool_input: {},
    ...overrides,
  };
}

/** null means "continue" (guard passed), non-null means "skip" */
function isSkip(result: GuardResult): boolean {
  return result !== null;
}

beforeEach(() => {
  vi.restoreAllMocks();
  vi.mocked(isAgentTeamsActive).mockReturnValue(false);
});

// =============================================================================
// guardFileExtension
// =============================================================================

describe('guardFileExtension', () => {
  it('continues for matching extension', () => {
    const input = makeInput({ tool_input: { file_path: '/src/app.ts' } });
    expect(guardFileExtension(input, 'ts')).toBeNull();
  });

  it('skips for non-matching extension', () => {
    const input = makeInput({ tool_input: { file_path: '/src/app.py' } });
    expect(isSkip(guardFileExtension(input, 'ts'))).toBe(true);
  });

  it('skips when no file_path', () => {
    const input = makeInput({ tool_input: {} });
    expect(isSkip(guardFileExtension(input, 'ts'))).toBe(true);
  });

  it('handles dotted extensions', () => {
    const input = makeInput({ tool_input: { file_path: '/a/b.tsx' } });
    expect(guardFileExtension(input, '.tsx')).toBeNull();
  });

  it('is case-insensitive', () => {
    const input = makeInput({ tool_input: { file_path: '/a/b.TSX' } });
    expect(guardFileExtension(input, 'tsx')).toBeNull();
  });

  it('matches any of multiple extensions', () => {
    const input = makeInput({ tool_input: { file_path: '/a/b.jsx' } });
    expect(guardFileExtension(input, 'ts', 'tsx', 'js', 'jsx')).toBeNull();
  });
});

