// =============================================================================
// guardPathPattern (also exercises globMatch)
// =============================================================================

describe('guardPathPattern', () => {
  it('matches simple glob with *', () => {
    const input = makeInput({ tool_input: { file_path: '/src/hooks/foo.ts' } });
    expect(guardPathPattern(input, '*hooks*')).toBeNull();
  });

  it('matches regex pattern', () => {
    const input = makeInput({ tool_input: { file_path: '/src/hooks/foo.ts' } });
    expect(guardPathPattern(input, /hooks/)).toBeNull();
  });

  it('skips when no pattern matches', () => {
    const input = makeInput({ tool_input: { file_path: '/src/app.ts' } });
    expect(isSkip(guardPathPattern(input, '*hooks*', /tests/))).toBe(true);
  });

  it('skips when no file_path', () => {
    expect(isSkip(guardPathPattern(makeInput({ tool_input: {} }), '*anything*'))).toBe(true);
  });

  it('matches glob with ? wildcard', () => {
    const input = makeInput({ tool_input: { file_path: '/src/a1b.ts' } });
    expect(guardPathPattern(input, '*a?b*')).toBeNull();
  });

  it('rejects glob with ? when char mismatch', () => {
    const input = makeInput({ tool_input: { file_path: '/src/aXXb.ts' } });
    // a?b expects exactly one char between a and b
    expect(isSkip(guardPathPattern(input, 'a?b'))).toBe(true);
  });
});

