// =============================================================================
// runGuards
// =============================================================================

describe('runGuards', () => {
  it('returns null when all guards pass', () => {
    const g1 = () => null as GuardResult;
    const g2 = () => null as GuardResult;
    expect(runGuards(makeInput(), g1, g2)).toBeNull();
  });

  it('returns first skip result', () => {
    const skip = { continue: true, exit_code: 0, suppressOutput: true } as GuardResult;
    const g1 = () => null as GuardResult;
    const g2 = () => skip;
    const g3 = vi.fn(() => null as GuardResult);

    const result = runGuards(makeInput(), g1, g2, g3);
    expect(result).toBe(skip);
    // g3 should not be called because g2 returned skip
    expect(g3).not.toHaveBeenCalled();
  });

  it('returns null for empty guards list', () => {
    expect(runGuards(makeInput())).toBeNull();
  });
});

